freq.set("a", 3);
freq.set("b", 1);

console.log(freq.get("a"));   // 3
console.log(freq.has("c"));   // false
console.log(freq.size);       // 2

freq.delete("b");
console.log(freq.size);       // 1

function charFreq(s: string): Map<string, number> {
  const freq: Map<string, number> = new Map();
  for (const ch of s) {
    freq.set(ch, (freq.get(ch) ?? 0) + 1);
  }
  return freq;
}

const counts = charFreq("abracadabra");
console.log(counts.get("a"));  // 5
console.log(counts.get("b"));  // 2

